class SMPArchitecture {
 public static void main(String[] args) {
 // Shared Memory
 int shared_memory = 10;

 // Multiple Processors
 Thread processor1 = new Thread(() -> {
 // Access shared memory
 System.out.println(shared_memory);
 });

 Thread processor2 = new Thread(() -> {
 // Access shared memory
 System.out.println(shared_memory);
 });

 processor1.start();
 processor2.start();
 }
